+export function getNextHandshakeState(
+  state: HandshakeState,
+  decisionMode: DecisionMode
+): HandshakeState {
+  if (state === "pending") {
+    return decisionMode === "accept" ? "accepted" : "rejected";
+  }
+  if (state === "rejected") {
+    return "request";
+  }
+  const idx = ORDER.indexOf(state as FlowState);
+  if (idx < 0) {
+    return "unconnected";
+  }
+  return ORDER[(idx + 1) % ORDER.length];
