+export function getPreviousHandshakeState(state: HandshakeState): HandshakeState {
+  if (state === "rejected") {
+    return "pending";
+  }
+  const idx = ORDER.indexOf(state as FlowState);
+  if (idx <= 0) {
+    return "unconnected";
+  }
+  return ORDER[idx - 1];
+}
